    const arg0 = ctx.args[0];
    const key = arg0?.kind === "literal" && typeof arg0.value === "string" ? arg0.value : null;

    // Handle thinBorder(color) helper from ./lib/helpers.ts
    // thinBorder("transparent") -> \`\${pixelVars.thin} solid transparent\`
